namespace ScraperBackendService.Core.Concurrency;/// <summary>/// Global rate limiter that enforces a minimum time interval between consecutive/// cache-miss requests to a provider, regardless of which concurrency slot is used./// </summary>/// <remarks>/// A semaphore gate serialises the check-wait-record cycle so that at most one/// caller at a time can pass the rate barrier. This guarantees a true global/// minimum interval of <c>RateLimitSeconds</c> between any two outgoing requests./// </remarks>public sealed class ProviderRateLimiter : IDisposable{    private readonly TimeSpan _minInterval;    private readonly SemaphoreSlim _gate = new(1, 1);    private DateTimeOffset _lastRequestTime;    private long _totalWaits;    private static readonly TimeSpan Epsilon = TimeSpan.FromMilliseconds(10);    /// <summary>    /// Gets the provider name for this rate limiter instance.    /// </summary>    public string ProviderName { get; }    /// <summary>    /// Initializes a new instance of the ProviderRateLimiter class.    /// </summary>    /// <param name="minInterval">Minimum interval between consecutive requests</param>    /// <param name="providerName">Optional provider name for identification</param>    public ProviderRateLimiter(TimeSpan minInterval, string? providerName = null)    {        _minInterval = minInterval;        ProviderName = providerName ?? "Unknown";    }    /// <summary>    /// Waits until the global rate limit allows the next request, then records    /// the current time so that subsequent callers will be delayed appropriately.    /// Thread-safe: only one caller passes through at a time.    /// </summary>    /// <param name="ct">Cancellation token</param>    /// <returns>Task that completes when the rate limit allows the request to proceed</returns>    public async Task WaitIfNeededAsync(CancellationToken ct)    {        if (_minInterval == TimeSpan.Zero)            return;        await _gate.WaitAsync(ct).ConfigureAwait(false);        try        {            var elapsed = DateTimeOffset.UtcNow - _lastRequestTime;            var remaining = _minInterval - elapsed;            if (remaining > Epsilon)            {                Interlocked.Increment(ref _totalWaits);                await Task.Delay(remaining, ct).ConfigureAwait(false);            }            // Stamp the time *before* releasing the gate so the next            // waiter sees the correct interval.            _lastRequestTime = DateTimeOffset.UtcNow;        }        finally        {            _gate.Release();        }    }    /// <summary>    /// Calculates how much time the next caller would need to wait.    /// </summary>    /// <returns>TimeSpan indicating estimated wait, or TimeSpan.Zero if no wait needed</returns>    public TimeSpan GetEstimatedWaitTime()    {        if (_minInterval == TimeSpan.Zero)            return TimeSpan.Zero;        var elapsed = DateTimeOffset.UtcNow - _lastRequestTime;        var remaining = _minInterval - elapsed;        return remaining > Epsilon ? remaining : TimeSpan.Zero;    }    /// <summary>    /// Clears the rate limit history.    /// </summary>    public void Reset()    {        _lastRequestTime = default;        Interlocked.Exchange(ref _totalWaits, 0);    }    /// <summary>    /// Gets statistics about rate limiter usage.    /// </summary>    public RateLimiterStatistics GetStatistics()    {        var elapsed = DateTimeOffset.UtcNow - _lastRequestTime;        return new RateLimiterStatistics        {            IsInCooldown = _lastRequestTime != default && elapsed < _minInterval,            TotalWaits = Interlocked.Read(ref _totalWaits),            MinInterval = _minInterval        };    }    /// <inheritdoc />    public void Dispose() => _gate.Dispose();}/// <summary>/// Rate limiter statistics./// </summary>public sealed class RateLimiterStatistics{    public bool IsInCooldown { get; set; }    public long TotalWaits { get; set; }    public TimeSpan MinInterval { get; set; }}